THE CLAIM:
{
 "title": "Frankfurt grid queue could push half the Year-1 orders to 2027",
 "narrative": "The model treats Germany as a diversified half of the market. But Frankfurt hosts about 75% of German capacity, so roughly 37% of Year-1 demand routes through one metro where grid connections now wait 24–36 months. If Frankfurt's 542 MW under construction slips past 2026, the largest tranche of Year-1 orders moves to 2027–28.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "Frankfurt grid connections wait 24–36 months; 542 MW awaits energization",
   "refs": [
    "digest:geo-DE#c15",
    "digest:geo-DE#c8",
    "digest:geo-DE#c14"
   ]
  },
  {
   "step": "propagation",
   "text": "Frankfurt is 75% of German capacity; deferred energization defers the biggest orders",
   "refs": [
    "digest:geo-DE#c1",
    "ledger:geo.DE"
   ]
  },
  {
   "step": "model-impact",
   "text": "DE share falls to 0.42 and Year-1 pace drops with it",
   "refs": [
    "ledger:geo.DE",
    "ledger:obtainableFactor"
   ]
  }
 ],
 "falsifier": "Grid operator commitments or Frankfurt data showing live IT load stepping up by more than 100 MW within Year-1.",
 "category": "exogenous",
 "evidence": [
  {
   "title": "Germany's Data Center Strategy vs. AI Energy Demand",
   "sourceType": "industry-report",
   "publisher": "innobu",
   "date": "2026-04-01",
   "excerpt": "In Frankfurt, 126 data centers account for up to 40 percent of city-wide power consumption, and new grid connections are unavailable until the mid-2030s. The Energy Efficiency Act requires operators to source 100 percent renewable electricity by January 2027, reuse at least 10 percent of waste heat from July 2026, and maintain a maximum PUE of 1.2 for new facilities.",
   "url": "https://www.innobu.com/en/articles/data-center-strategy-ai-energy-demand.html",
   "attached": true
  },
  {
   "title": "Frankfurt's Data Center Market Has Hit a Physical Wall",
   "sourceType": "industry-report",
   "publisher": "KiTalent",
   "date": "2026-03-01",
   "excerpt": "Available utility capacity for new large-scale developments within Frankfurt city limits is effectively zero. High-voltage grid connections now carry wait times of 24 to 36 months. The Energy Efficiency Act mandates PUE of 1.2 or better from 2026 onward.",
   "url": "https://kitalent.com/articles/frankfurt-data-center-talent-crisis",
   "attached": true
  },
  {
   "title": "TenneT, Uniper Partner for Power Station for Frankfurt Region",
   "sourceType": "industry-report",
   "publisher": "Rigzone",
   "date": "2026-01-25",
   "excerpt": "Uniper and TenneT agreed to develop a new central network node in Grosskrotzenburg to serve data center-driven growth in power demand in the greater Frankfurt area, targeting to start operation earlier than planned.",
   "url": "https://www.rigzone.com/news/tennet_uniper_partner_for_power_station_for_frankfurt_region-25-jan-2026-182841-article/",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "geo.DE",
  "label": "Germany",
  "kind": "estimated",
  "value": 0.5,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": "geography",
  "dimensionValue": "DE",
  "sensitivityRange": {
   "low": 0.42,
   "high": 0.53
  },
  "funnelActive": true,
  "derivation": {
   "method": "Top-down capacity apportionment",
   "expression": "DE colo 1,737 MW ÷ CE-7 colo 3,451 MW (Statista 2025) = 0.503 → 0.50 (normalized)",
   "crossCheck": "Installed-IT-load method (BMWK >2,700 MW ÷ CE-7 installed) → 0.42 — sets the low end"
  },
  "provenance": {
   "rationale": "Two independent capacity methods bracket 0.42–0.53; colo-scope figure is primary → inferred.",
   "promotionPath": "Reconcile colo vs total-installed scopes with one 2025 vendor-revenue split → verified."
  },
  "evidence": [
   {
    "title": "Europe colocation data center IT power supply by country, 2024–2031",
    "sourceType": "industry-report",
    "publisher": "Statista",
    "date": "2026-02-06",
    "excerpt": "Germany 1,737 MW of colocation and scale-colocation IT power in 2025 — the largest CE base (NL 951, CH 274, PL 228, CZ 79, AT 68).",
    "attached": true
   },
   {
    "title": "Status and development of the German data centre landscape",
    "sourceType": "industry-report",
    "publisher": "BMWK (Federal Ministry for Economic Affairs)",
    "date": "2025-03",
    "excerpt": "With over 2,000 data centres and an installed IT power demand of over 2,700 MW, Germany is already the largest centre for digital infrastructure in Europe.",
    "attached": true
   }
  ]
 },
 {
  "id": "obtainableFactor",
  "label": "Year-1 obtainable share of SAM",
  "kind": "assumption",
  "value": 0.01,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 0.005,
   "high": 0.03
  },
  "funnelActive": true,
  "derivation": {
   "method": "Benchmark anchoring",
   "expression": "Prospeo assigns 1% of SAM to YEAR 1 (3% and 5% are Years 2–3) — the prior 3% read the Year-2 figure as Year 1. Corrected to 1%; the Tractian comparable (first-year ~$1.2M against a multi-$B market) sits below 1%.",
   "crossCheck": "Early-procurement mechanism (DC electrical gear locked 12–24mo before fit-out) independently supports ≤2%; open 2026 EU rack-PDU tenders keep 2–3% inside the band."
  },
  "provenance": {
   "rationale": "Refinement cycle 1 caught the benchmark-period misread — the value now follows the source's own Year-1 figure, band 0.5–3%.",
   "promotionPath": "Replace with pipeline-based model once first CE deals close (win-rate × cycle time × capacity)."
  },
  "evidence": [
   {
    "title": "Addressable markets — SOM benchmarks",
    "sourceType": "analyst-estimate",
    "publisher": "Prospeo",
    "date": null,
    "excerpt": "SOM benchmarks that won't get you laughed out of the room: 1% of SAM in Year 1, 3% in Year 2, 5% in Year 3.",
    "attached": true
   },
   {
    "title": "Serviceable Obtainable Market (SOM) — early-stage ranges",
    "sourceType": "analyst-estimate",
    "publisher": "IdeaPlan",
    "date": "2024",
    "excerpt": "For early-stage companies, SOM is typically 1-5% of SAM. For growing companies with product-market fit, SOM can reach 10-20% of SAM.",
    "attached": true
   }
  ]
 }
]

